import 'package:injectable/injectable.dart'; import 'package:wakelock_plus/wakelock_plus.dart'; import '../utils/app_logger.dart'; @singleton class ScreenWakeService { Future<void> keepAwake() async { try { await WakelockPlus.enable(); AppLogger.debug('Wake lock enabled'); } catch (e) { AppLogger.warning('Wake lock: $e'); } } Future<void> release() async { try { await WakelockPlus.disable(); AppLogger.debug('Wake lock released'); } catch (e) { AppLogger.warning('Wake lock release: $e'); } } }